def find_largest_subset(arr, target):
    curr_sums, max_sum_list = [], []
    for num in arr:
        for curr_sum in curr_sums[:]:
            new_sum = curr_sum + num
            if new_sum == target:
                if new_sum > sum(max_sum_list):
                    max_sum_list = curr_sum + [num]
            else:
                curr_sums.append(new_sum)
    return max_sum_list

