function highestCommonFactor(m, n) {
  if (m === 0 || n === 0) {
      return 0;
  }

  let a = Math.max(m, n);
  let b = Math.min(m, n);

  while (b !== 0) {
      let c = b;
      b = a % b;
      a = c;
  }

  return a;
}

