          i++; 
      } 
      else
      { 
          array[k] = rightArray[j]; 
          j++; 
      } 
      k++; 
  } 

  // Copy the remaining elements  
  while (i < sizeof(leftArray)) : 
  { 
      array[k] = leftArray[i]; 
      i++; 
