        return arr
    pivot = arr[len(arr)//2]
    left, right, equal = [], [], []
    for x in arr:
        if x < pivot:
            left.append(x)
        elif x > pivot:
            right.append(x)
        else:
            equal.append(x)
    return quicksort(left) + equal + quicksort(right)

