// Function to reverse any sequence starting 
// with pointer begin and ending with pointer end 
void ReverseString(char* begin, char* end) 
{ 
    char temp; 
    while (begin < end) { 
        temp = *begin; 
        *begin++ = *end; 
        *end-- = temp; 
    } 
} 

// Function to reverse words*/ 
void reverseWords(char* s) 
{ 
    char* word_begin = s; 

    // Word boundary 
    char* temp = s; 

    // Reversing individual words as 
    // explained in the first step 
    while (*temp) { 
        temp++; 
        if (*temp == '\0') { 
            ReverseString(word_begin, temp - 1); 
        } 
        else if (*temp == ' ') { 
            ReverseString(word_begin, temp - 1); 
            word_begin = temp + 1; 
        } 
    } 

    // Reverse the entire string 
    ReverseString(s, temp - 1); 
} 

int main() 
{ 
    char s[] = "Geeks For Geeks"; 
    reverseWords(s); 
    printf("%s", s); 
    return 0; 
}

