#include<stdio.h>

int isPrime(int n) 
{ 
    for (int i = 2; i <= n/2; i++) 
    { 
        if (n % i == 0) 
            return 0; 
    } 
    return 1; 
} 

void findPrime(int arr[], int n) 
{ 
    int result[n];
    int k = 0;
    for (int i = 0; i < n; i++) 
    { 
        if (isPrime(arr[i]) == 1) 
        { 
            result[k] = arr[i];
            k++;
        } 
    } 

    for (int i = 0; i < k; i++) 
        printf("%d ", result[i]); 
} 

int main() 
{ 
