fn lowestCommonAncestor(root: &TreeNode, p: &TreeNode, q: &TreeNode) -> i32 {
 if root == nil {
  return -1;
 }

 if root == p || root == q {
  return root.val;
 }

 let left = lowestCommonAncestor(root.left, p, q);
 let right = lowestCommonAncestor(root.right, p, q);

 if left != -1 && right != -1 {
  return root.val;
 }

 return left != -1 ? left : right;
}

