library(zoo)

exponential_moving_average <- function(x, n, beta) {
  EMA <- 0
  for (i in 1:length(x)) {
     if (i == 1) {
       EMA[i] <- x[i]
     } else {
       EMA[i] <- ((beta * x[i]) + ((1 - beta) * EMA[i - 1]))
     } 
  }

  ma_x <- as.numeric(rollapply(EMA, n, mean, fill = NA, align = "right"))
  return(ma_x)
}

