    int highest = arr[0]; 
    for (int i = 1; i < arr.length; i++) {
      highest = Math.max(highest, arr[i]); 
    }
    return highest; 
  }

  public static void main(String[] args) {
    int[] arr = {1, 2, 4, 7, 10}; 
    System.out.println(findHighest(arr)); 
  }
