				// print the character along with its 
				// frequency 
				System.out.print(str.charAt(i)); 
				System.out.print(freq[str.charAt(i)] + " "); 

				// update frequency of str.charAt(i) to 
				// 0 so that the same character is not printed 
				// again 
				freq[str.charAt(i)] = 0; 
			} 
		} 
	} 

