class LinkedList:

    def __init__(self, head=None):
        self.head = head

    def insert(self, node):
        current = self.head
        if not self.head:
            self.head = node
        else:
            while current.next:
                current = current.next
            current.next = node

     def delete_node(self, data):
        current = self.head
        while current.data != data and current.next is not None:
