### Instruction:
How would you implement a Binary Search Tree in Java?

### Response:
public class BinarySearchTree { 

  /* Class containing left, right and root nodes */
  class Node { 
    int key; 
    Node left, right; 

    public Node(int item) {
		key = item; 
		left = right = null; 
	} 
  } 

  // Root of BST 
  Node root; 

  // Constructor 
  BinarySearchTree() {  
	root = null;  
  } 

  // This method mainly calls insertRec() 
  void insert(int key) { 
	 root = insertRec(root, key); 
  } 

  /* A recursive function to insert a new key in BST */
  Node insertRec(Node root, int key) { 

	// When the tree is empty, return a new node 
	if (root == null) { 
		root = new Node(key); 
		return root; 
	}

	// Otherwise, recurr down the tree 
	if (key < root.key) 
		root.left = insertRec(root.left, key); 
	else if (key > root.key) 
		root.right = insertRec(root.right, key);

	// return the root 
	return root; 
  } 

}

